pub fn get_or_init(&self, f: impl FnOnce() -> Pin<Box<T>>) -> Pin<&T> {
    let ptr = self.ptr.load(Acquire);
    match unsafe { ptr.as_ref() } {
        Some(val) => unsafe { Pin::new_unchecked(val) },
        None => self.initialize(f),
    }
}
